SELECT "contacts"."id", "contacts"."code", "contacts"."categories", "contacts"."organization_id", "contacts"."first_name", "contacts"."middle_name", "contacts"."last_name", "contacts"."status", COALESCE(TO_CHAR((("contacts"."created_date"::TIMESTAMP + "contacts"."created_time"::INTERVAL) AT TIME ZONE 'UTC' AT TIME ZONE 'Asia/Manila')::DATE, 'mm/dd/YYYY'), '') AS "created_date", COALESCE(TO_CHAR((("contacts"."updated_date"::TIMESTAMP + "contacts"."updated_time"::INTERVAL) AT TIME ZONE 'UTC' AT TIME ZONE 'Asia/Manila')::DATE, 'mm/dd/YYYY'), '') AS "updated_date", ((("contacts"."created_date"::TIMESTAMP + "contacts"."created_time"::INTERVAL) AT TIME ZONE 'UTC' AT TIME ZONE 'Asia/Manila'))::time::text AS created_time, ((("contacts"."updated_date"::TIMESTAMP + "contacts"."updated_time"::INTERVAL) AT TIME ZONE 'UTC' AT TIME ZONE 'Asia/Manila'))::time::text AS updated_time, "contacts"."created_by", "contacts"."updated_by", "contacts"."previous_status", COALESCE( ( SELECT JSONB_AGG(elem ) FROM (SELECT JSONB_BUILD_OBJECT('email', "contact_emails"."email", 'is_primary', "contact_emails"."is_primary") AS elem FROM contact_emails contact_emails WHERE (contact_emails.tombstone = 0) AND "contacts"."id" = "contact_emails"."contact_id") sub ), '[]' ) AS contact_emails, "contacts"."id", "contacts"."code", "contacts"."categories", "contacts"."organization_id", "contacts"."first_name", "contacts"."middle_name", "contacts"."last_name", "contacts"."status", COALESCE(TO_CHAR((("contacts"."created_date"::TIMESTAMP + "contacts"."created_time"::INTERVAL) AT TIME ZONE 'UTC' AT TIME ZONE 'Asia/Manila')::DATE, 'mm/dd/YYYY'), '') AS "created_date", COALESCE(TO_CHAR((("contacts"."updated_date"::TIMESTAMP + "contacts"."updated_time"::INTERVAL) AT TIME ZONE 'UTC' AT TIME ZONE 'Asia/Manila')::DATE, 'mm/dd/YYYY'), '') AS "updated_date", ((("contacts"."created_date"::TIMESTAMP + "contacts"."created_time"::INTERVAL) AT TIME ZONE 'UTC' AT TIME ZONE 'Asia/Manila'))::time::text AS created_time, ((("contacts"."updated_date"::TIMESTAMP + "contacts"."updated_time"::INTERVAL) AT TIME ZONE 'UTC' AT TIME ZONE 'Asia/Manila'))::time::text AS updated_time, "contacts"."created_by", "contacts"."updated_by", "contacts"."previous_status", COALESCE( ( SELECT JSONB_AGG(elem ) FROM (SELECT JSONB_BUILD_OBJECT('phone_number_raw', "contact_phone_numbers"."phone_number_raw") AS elem FROM contact_phone_numbers contact_phone_numbers WHERE (contact_phone_numbers.tombstone = 0) AND "contacts"."id" = "contact_phone_numbers"."contact_id") sub ), '[]' ) AS contact_phone_numbers, "contacts"."id", "contacts"."code", "contacts"."categories", "contacts"."organization_id", "contacts"."first_name", "contacts"."middle_name", "contacts"."last_name", "contacts"."status", COALESCE(TO_CHAR((("contacts"."created_date"::TIMESTAMP + "contacts"."created_time"::INTERVAL) AT TIME ZONE 'UTC' AT TIME ZONE 'Asia/Manila')::DATE, 'mm/dd/YYYY'), '') AS "created_date", COALESCE(TO_CHAR((("contacts"."updated_date"::TIMESTAMP + "contacts"."updated_time"::INTERVAL) AT TIME ZONE 'UTC' AT TIME ZONE 'Asia/Manila')::DATE, 'mm/dd/YYYY'), '') AS "updated_date", ((("contacts"."created_date"::TIMESTAMP + "contacts"."created_time"::INTERVAL) AT TIME ZONE 'UTC' AT TIME ZONE 'Asia/Manila'))::time::text AS created_time, ((("contacts"."updated_date"::TIMESTAMP + "contacts"."updated_time"::INTERVAL) AT TIME ZONE 'UTC' AT TIME ZONE 'Asia/Manila'))::time::text AS updated_time, "contacts"."created_by", "contacts"."updated_by", "contacts"."previous_status", COALESCE( ( SELECT JSONB_AGG(elem ) FROM (SELECT JSONB_BUILD_OBJECT('id', "created_by_account_organizations"."id", 'contact_id', "created_by_account_organizations"."contact_id") AS elem FROM account_organizations created_by_account_organizations WHERE (created_by_account_organizations.tombstone = 0) AND "contacts"."created_by" = "created_by_account_organizations"."id") sub ), '[]' ) AS created_by_account_organizations, "created_by_account_organizations"."id", "created_by_account_organizations"."contact_id", COALESCE( ( SELECT JSONB_AGG(elem ) FROM (SELECT JSONB_BUILD_OBJECT('id', "created_by"."id", 'first_name', "created_by"."first_name", 'last_name', "created_by"."last_name") AS elem FROM account_organizations created_by_account_organizations LEFT JOIN contacts created_by ON "created_by_account_organizations"."contact_id" = "created_by"."id" WHERE (created_by.tombstone = 0) AND "contacts"."created_by" = "created_by_account_organizations"."id") sub ), '[]' ) AS created_by, "contacts"."id", "contacts"."code", "contacts"."categories", "contacts"."organization_id", "contacts"."first_name", "contacts"."middle_name", "contacts"."last_name", "contacts"."status", COALESCE(TO_CHAR((("contacts"."created_date"::TIMESTAMP + "contacts"."created_time"::INTERVAL) AT TIME ZONE 'UTC' AT TIME ZONE 'Asia/Manila')::DATE, 'mm/dd/YYYY'), '') AS "created_date", COALESCE(TO_CHAR((("contacts"."updated_date"::TIMESTAMP + "contacts"."updated_time"::INTERVAL) AT TIME ZONE 'UTC' AT TIME ZONE 'Asia/Manila')::DATE, 'mm/dd/YYYY'), '') AS "updated_date", ((("contacts"."created_date"::TIMESTAMP + "contacts"."created_time"::INTERVAL) AT TIME ZONE 'UTC' AT TIME ZONE 'Asia/Manila'))::time::text AS created_time, ((("contacts"."updated_date"::TIMESTAMP + "contacts"."updated_time"::INTERVAL) AT TIME ZONE 'UTC' AT TIME ZONE 'Asia/Manila'))::time::text AS updated_time, "contacts"."created_by", "contacts"."updated_by", "contacts"."previous_status", COALESCE( ( SELECT JSONB_AGG(elem ) FROM (SELECT JSONB_BUILD_OBJECT('id', "updated_by_account_organizations"."id", 'contact_id', "updated_by_account_organizations"."contact_id") AS elem FROM account_organizations updated_by_account_organizations WHERE (updated_by_account_organizations.tombstone = 0) AND "contacts"."updated_by" = "updated_by_account_organizations"."id") sub ), '[]' ) AS updated_by_account_organizations, "updated_by_account_organizations"."id", "updated_by_account_organizations"."contact_id", COALESCE( ( SELECT JSONB_AGG(elem ) FROM (SELECT JSONB_BUILD_OBJECT('id', "updated_by"."id", 'first_name', "updated_by"."first_name", 'last_name', "updated_by"."last_name") AS elem FROM account_organizations updated_by_account_organizations LEFT JOIN contacts updated_by ON "updated_by_account_organizations"."contact_id" = "updated_by"."id" WHERE (updated_by.tombstone = 0) AND "contacts"."updated_by" = "updated_by_account_organizations"."id") sub ), '[]' ) AS updated_by FROM contacts LEFT JOIN LATERAL (SELECT "joined_contact_emails"."email", "joined_contact_emails"."is_primary" FROM "contact_emails" "joined_contact_emails" WHERE (joined_contact_emails.tombstone = 0) AND "joined_contact_emails"."contact_id" = "contacts"."id" ) AS "contact_emails" ON TRUE LEFT JOIN LATERAL (SELECT "joined_contact_phone_numbers"."phone_number_raw" FROM "contact_phone_numbers" "joined_contact_phone_numbers" WHERE (joined_contact_phone_numbers.tombstone = 0) AND "joined_contact_phone_numbers"."contact_id" = "contacts"."id" ) AS "contact_phone_numbers" ON TRUE LEFT JOIN LATERAL (SELECT "joined_created_by_account_organizations"."id", "joined_created_by_account_organizations"."contact_id" FROM "account_organizations" "joined_created_by_account_organizations" WHERE (joined_created_by_account_organizations.tombstone = 0) AND "joined_created_by_account_organizations"."id" = "contacts"."created_by" ) AS "created_by_account_organizations" ON TRUE LEFT JOIN LATERAL (SELECT "joined_created_by"."id", "joined_created_by"."first_name", "joined_created_by"."last_name" FROM "contacts" "joined_created_by" WHERE (joined_created_by.tombstone = 0) AND "joined_created_by"."id" = "created_by_account_organizations"."contact_id" ) AS "created_by" ON TRUE LEFT JOIN LATERAL (SELECT "joined_updated_by_account_organizations"."id", "joined_updated_by_account_organizations"."contact_id" FROM "account_organizations" "joined_updated_by_account_organizations" WHERE (joined_updated_by_account_organizations.tombstone = 0) AND "joined_updated_by_account_organizations"."id" = "contacts"."updated_by" ) AS "updated_by_account_organizations" ON TRUE LEFT JOIN LATERAL (SELECT "joined_updated_by"."id", "joined_updated_by"."first_name", "joined_updated_by"."last_name" FROM "contacts" "joined_updated_by" WHERE (joined_updated_by.tombstone = 0) AND "joined_updated_by"."id" = "updated_by_account_organizations"."contact_id" ) AS "updated_by" ON TRUE WHERE (contacts.tombstone = 0) GROUP BY contacts.id, "contacts"."categories", "contacts"."organization_id", "contacts"."first_name", "contacts"."middle_name", "contacts"."last_name", "updated_by"."id", "updated_by"."first_name", "updated_by"."last_name", "contacts"."code", "contacts"."categories", "contacts"."organization_id", "contacts"."first_name", "contacts"."middle_name", "contacts"."last_name", "contacts"."status", "contacts"."created_date", "contacts"."updated_date", "contacts"."created_time", "contacts"."updated_time", "contacts"."created_by", "contacts"."updated_by", "contacts"."previous_status", "updated_by_account_organizations"."id", "updated_by_account_organizations"."contact_id", "created_by_account_organizations"."id", "created_by_account_organizations"."contact_id", "contact_emails"."email", "contact_emails"."is_primary", "contact_phone_numbers"."phone_number_raw", "created_by"."id", "created_by"."first_name", "created_by"."last_name" ORDER BY LOWER(contacts.id) ASC LIMIT 100